import { useEffect, useState } from "react";
import api from "../api";

const PAGE_SIZE = 10;

// Chuẩn hoá dữ liệu có/không phân trang
function normalizeList(d) {
    return Array.isArray(d)
        ? { list: d, pages: 1, total: d.length }
        : {
            list: d?.content || [],
            pages: d?.totalPages ?? 1,
            total: d?.totalElements ?? (d?.content?.length || 0),
        };
}

// Map enum -> nhãn tiếng Việt
const GROUPS = [
    { v: "VIP", label: "VIP" },
    { v: "POTENTIAL", label: "Tiềm năng" },
    { v: "NORMAL", label: "Thường" },
];

const REGIONS = [
    { v: "NORTH", label: "Miền Bắc" },
    { v: "CENTRAL", label: "Miền Trung" },
    { v: "SOUTH", label: "Miền Nam" },
    { v: "OTHER", label: "Khác" },
];

export default function Customers() {
    const [rows, setRows] = useState([]);
    const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(1);
    const [loading, setLoading] = useState(true);

    // tìm kiếm đơn giản theo tên
    const [q, setQ] = useState("");

    // modal state
    const [show, setShow] = useState(false);
    const [editing, setEditing] = useState(null);
    const [form, setForm] = useState({
        name: "",
        customerGroup: "NORMAL",
        region: "OTHER",
        phone: "",
        email: "",
        address: "",
        ownerId: "",
    });

    useEffect(() => {
        load();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [page]);

    async function load() {
        setLoading(true);
        try {
            const { data } = await api.get("/api/customers", {
                params: { page, size: PAGE_SIZE, sort: "id,desc", q: q || undefined },
            });
            const { list, pages } = normalizeList(data);
            setRows(
                list.map((c) => ({
                    id: c.id,
                    name: c.name,
                    customerGroup: c.customerGroup, // VIP / POTENTIAL / NORMAL
                    region: c.region, // NORTH / CENTRAL / SOUTH / OTHER
                    phone: c.phone,
                    email: c.email,
                    address: c.address,
                    ownerId: c.ownerId,
                    ownerName: c.ownerName,
                }))
            );
            setTotalPages(pages);
        } catch (e) {
            console.error(e);
            setRows([]);
            setTotalPages(1);
        } finally {
            setLoading(false);
        }
    }

    function openCreate() {
        setEditing(null);
        setForm({
            name: "",
            customerGroup: "NORMAL",
            region: "OTHER",
            phone: "",
            email: "",
            address: "",
            ownerId: "",
        });
        setShow(true);
    }

    function openEdit(row) {
        setEditing(row);
        setForm({
            name: row.name || "",
            customerGroup: row.customerGroup || "NORMAL",
            region: row.region || "OTHER",
            phone: row.phone || "",
            email: row.email || "",
            address: row.address || "",
            ownerId: row.ownerId || "",
        });
        setShow(true);
    }

    async function save(e) {
        e.preventDefault();

        // payload khớp backend (KHÔNG có contactPerson)
        const payload = {
            name: form.name?.trim(),
            customerGroup: form.customerGroup,
            region: form.region,
            phone: form.phone?.trim() || null,
            email: form.email?.trim() || null,
            address: form.address?.trim() || null,
            ownerId:
                (form.ownerId !== "" && !Number.isNaN(Number(form.ownerId)))
                    ? Number(form.ownerId)
                    : null,
        };

        try {
            if (editing) {
                await api.put(`/api/customers/${editing.id}`, payload);
            } else {
                await api.post("/api/customers", payload);
            }
            setShow(false);
            await load();
        } catch (err) {
            alert(
                err?.response?.data?.message ||
                err?.response?.data?.error ||
                "Lưu khách hàng thất bại"
            );
        }
    }

    async function remove(row) {
        if (!window.confirm(`Xoá khách hàng "${row.name}"?`)) return;
        try {
            await api.delete(`/api/customers/${row.id}`);
            await load();
        } catch (err) {
            alert(
                err?.response?.data?.message ||
                err?.response?.data?.error ||
                "Xoá khách hàng thất bại"
            );
        }
    }

    function labelOf(arr, v) {
        return arr.find((x) => x.v === v)?.label || v || "-";
    }

    return (
        <div className="space-y-4">
            {/* Header */}
            <div className="flex flex-wrap items-center justify-between gap-3">
                <div>
                    <h2 className="text-lg font-semibold">Khách hàng</h2>
                    <p className="text-sm text-slate-500">Quản lý thông tin & phân loại</p>
                </div>
                <div className="flex items-center gap-2">
                    <div className="flex items-center gap-2">
                        <input
                            value={q}
                            onChange={(e) => setQ(e.target.value)}
                            placeholder="Tìm theo tên…"
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                        />
                        <button
                            onClick={() => {
                                setPage(0);
                                load();
                            }}
                            className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                        >
                            Tìm
                        </button>
                    </div>
                    <button
                        onClick={openCreate}
                        className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700"
                    >
                        Thêm khách hàng
                    </button>
                </div>
            </div>

            {/* Table */}
            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full text-sm">
                        <thead className="bg-indigo-50 text-slate-600">
                        <tr>
                            <th className="px-4 py-3 text-left">Tên</th>
                            <th className="px-4 py-3 text-left">Nhóm</th>
                            <th className="px-4 py-3 text-left">Khu vực</th>
                            <th className="px-4 py-3 text-left">Điện thoại</th>
                            <th className="px-4 py-3 text-left">Email</th>
                            <th className="px-4 py-3 text-left">Địa chỉ</th>
                            <th className="px-4 py-3 text-left">Owner</th>
                            <th className="px-4 py-3 text-right">Thao tác</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {loading ? (
                            <tr>
                                <td className="px-4 py-6" colSpan={8}>
                                    Đang tải…
                                </td>
                            </tr>
                        ) : rows.length === 0 ? (
                            <tr>
                                <td className="px-4 py-6" colSpan={8}>
                                    Chưa có dữ liệu
                                </td>
                            </tr>
                        ) : (
                            rows.map((c) => (
                                <tr key={c.id} className="hover:bg-indigo-50/40">
                                    <td className="px-4 py-3 font-medium">{c.name}</td>
                                    <td className="px-4 py-3">
                                        {labelOf(GROUPS, c.customerGroup)}
                                    </td>
                                    <td className="px-4 py-3">{labelOf(REGIONS, c.region)}</td>
                                    <td className="px-4 py-3">{c.phone || "-"}</td>
                                    <td className="px-4 py-3">{c.email || "-"}</td>
                                    <td className="px-4 py-3">{c.address || "-"}</td>
                                    <td className="px-4 py-3">
                                        {c.ownerName || c.ownerId || "-"}
                                    </td>
                                    <td className="px-4 py-3 text-right">
                                        <div className="inline-flex gap-2">
                                            <button
                                                onClick={() => openEdit(c)}
                                                className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100"
                                            >
                                                Sửa
                                            </button>
                                            <button
                                                onClick={() => remove(c)}
                                                className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100"
                                            >
                                                Xóa
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Pagination */}
            <div className="flex gap-2">
                <button
                    className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                    onClick={() => setPage((p) => Math.max(0, p - 1))}
                    disabled={page <= 0}
                >
                    ← Trước
                </button>
                <div className="px-3 py-1.5 text-sm">
                    Trang {page + 1}/{totalPages}
                </div>
                <button
                    className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                    onClick={() => setPage((p) => p + 1)}
                    disabled={page + 1 >= totalPages}
                >
                    Sau →
                </button>
            </div>

            {/* Modal (KHÔNG có Liên hệ) */}
            {show && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-3xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">
                                {editing ? "Sửa khách hàng" : "Thêm khách hàng"}
                            </div>
                            <button
                                className="text-slate-500 hover:text-slate-700"
                                onClick={() => setShow(false)}
                            >
                                Đóng
                            </button>
                        </div>

                        <form
                            onSubmit={save}
                            className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4"
                        >
                            <div>
                                <label className="text-sm text-slate-600">Tên</label>
                                <input
                                    required
                                    value={form.name}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, name: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Nhóm</label>
                                <select
                                    value={form.customerGroup}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, customerGroup: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    {GROUPS.map((g) => (
                                        <option key={g.v} value={g.v}>
                                            {g.label}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Khu vực</label>
                                <select
                                    value={form.region}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, region: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    {REGIONS.map((r) => (
                                        <option key={r.v} value={r.v}>
                                            {r.label}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Điện thoại</label>
                                <input
                                    value={form.phone}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, phone: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Email</label>
                                <input
                                    type="email"
                                    value={form.email}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, email: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Địa chỉ</label>
                                <input
                                    value={form.address}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, address: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">
                                    Owner ID (tuỳ backend)
                                </label>
                                <input
                                    value={form.ownerId}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, ownerId: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div className="md:col-span-2 flex items-center justify-end gap-2 pt-2">
                                <button
                                    type="button"
                                    className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                                    onClick={() => setShow(false)}
                                >
                                    Huỷ
                                </button>
                                <button className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">
                                    Lưu
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
